            "empty".to_string(),
        ],
        cwd: Some(ws),
    })
}

/// Open a fresh empty viewer as a new tiled pane. Returns its id when
/// Zellij accepts the spawn (so the floor can mark the re-spawn in flight).
fn spawn_empty_viewer(&mut self) -> Option<PaneId> {
    let command = self.empty_viewer_command()?;
    open_command_pane(command, BTreeMap::new())
}

/// Open a fresh empty viewer in place of `target`, a held/exited pane the
/// floor is replacing. Swapping in place keeps a dead pane from lingering
/// underneath the new viewer, matching the cockpit's swap-in-place model.
fn respawn_empty_viewer_in_place(&mut self, target: PaneId) -> Option<PaneId> {
    let command = self.empty_viewer_command()?;
    open_command_pane_in_place_of_pane_id(target, command, false, BTreeMap::new())
}

