1	//! `panopt _viewer` - a long-lived cockpit content pane.
2	//!
3	//! Renders one item from the project's `.panopt/` projection - a list of
4	//! items - or, for the todo and scratchpad kinds, hosts the matching shared
5	//! editable form ([`crate::todo_form`] / [`crate::scratchpad_form`]). The
6	//! sidebar plugin re-points the pane at a different item by writing a routing
7	//! file the viewer polls; switching item saves the outgoing item's scroll
8	//! position and restores the incoming one's (see [`crate::viewstate`]).
9	//!
10	//! Index views come from the projected `.panopt/*.md` files, which the daemon
11	//! keeps current. Todos and scratchpads are special: the viewer opens an MCP
12	//! session and renders the matching form against live `todo_get` /
13	//! `scratchpad_get` data, autosaving on a debounce. The pane is long-lived:
14	//! it closes only when the user presses Ctrl-C, never on its own.
15	
16	use std::path::{Path, PathBuf};
17	use std::time::{Duration, Instant, SystemTime};
18	
19	use std::io::stdout;
20	
21	use anyhow::{Context, Result};
22	use crossterm::event::{
23	    self, DisableBracketedPaste, DisableMouseCapture, EnableBracketedPaste, EnableMouseCapture,
24	    Event, KeyCode, KeyEvent, KeyEventKind, KeyModifiers, MouseButton, MouseEvent, MouseEventKind,
25	};
26	use crossterm::execute;
27	use ratatui::layout::{Constraint, Layout, Rect};
28	use ratatui::style::{Color, Modifier, Style};
29	use ratatui::text::{Line, Text};
30	use ratatui::widgets::{Paragraph, Wrap};
31	use ratatui::{DefaultTerminal, Frame};
32	use serde_json::{json, Value};
33	
34	use crate::mcpclient::Client;
35	use crate::scratchpad_form::ScratchpadForm;
36	use crate::todo::observer_url;
37	use crate::todo_form::TodoForm;
38	use crate::viewstate::{self, ViewState};
39	
40	/// How often the viewer wakes to poll the routing file and refresh content.
41	const TICK: Duration = Duration::from_millis(250);
42	/// The shortest gap between re-reads of the displayed content file.
43	const REFRESH: Duration = Duration::from_millis(800);
44	/// How long an unsaved scalar-field edit waits before the viewer flushes it.
45	const DEBOUNCE: Duration = Duration::from_millis(300);
46	
47	/// What a viewer pane is currently showing.
48	#[derive(Clone, Debug, PartialEq, Eq)]
49	enum Target {
50	    Todo(u64),
51	    /// A brand-new todo, not yet persisted. The form sends `todo_create` on
52	    /// the first autosave with a non-empty title; from then on it behaves
53	    /// like a `Todo(id)`.
54	    NewTodo,
55	    Scratchpad(u64),
56	    /// A brand-new scratchpad, not yet persisted. The form sends
57	    /// `scratchpad_create` on the first autosave with a non-empty title; from
58	    /// then on it behaves like a `Scratchpad(id)`.
59	    NewScratchpad,
60	    TodoList,
61	    ScratchpadList,
62	    Empty,
63	}
64	
65	impl Target {
66	    /// Parse a routing payload's `kind`/`id` pair into a target. The `empty`
67	    /// kind lets the sidebar clear the viewer when nothing is selected; the
68	    /// `new-todo` / `new-scratchpad` kinds open blank forms.
69	    fn parse(kind: &str, id: Option<u64>) -> Option<Target> {
70	        match (kind, id) {

