/// Build the launch command for a fresh empty `_viewer` in its own routing
/// slot, writing the slot's routing file as a side effect. `None` when
/// permissions are not yet granted (no workspace). Shared by the user-
/// driven [`Self::spawn_blank_pane`] and the floor's automatic re-spawn so
/// both produce an identical empty viewer.
fn empty_viewer_command(&mut self) -> Option<CommandToRun> {
    let ws = self.launch_cwd()?;
    let slot_name = self.allocate_viewer_slot();
    write_routing("empty", None, &slot_name);
    Some(CommandToRun {
        path: PathBuf::from(&self.panopt_bin),
        args: vec![
            "_viewer".to_string(),
            "--slot".to_string(),
            slot_name,
            "--port".to_string(),
            self.port.clone(),
            "--kind".to_string(),
            "empty".to_string(),
        ],
        cwd: Some(ws),
    })
}

/// Open a fresh empty viewer as a new tiled pane. Returns its id when
/// Zellij accepts the spawn (so the floor can mark the re-spawn in flight).
fn spawn_empty_viewer(&mut self) -> Option<PaneId> {
    let command = self.empty_viewer_command()?;
    open_command_pane(command, BTreeMap::new())
}

