/// Count live content panes across the whole session - the cockpit floor.
/// `self.panes` already excludes the five plugin panes (skipped at ingest),
/// so this counts only right-side content. Suppressed-but-running panes are
/// included (they are swappable content, just hidden); exited/held panes
/// and floating overlays (search popup, gate dialogs) are excluded. Used by
/// [`PanoptPane::gate_close_focus`] to refuse the last close and by
/// [`PanoptPane::ensure_content_floor`] to decide when to re-spawn. Counted
/// session-wide, not per-tab, so a viewer living in another tab still
/// satisfies the floor and the gatekeeper never spawns into the wrong tab.
fn content_pane_count(&self) -> usize {
    self.panes
        .iter()
        .filter(|p| !p.floating && !p.exited)
        .count()
}

/// Guarantee at least one live content pane exists. Every teardown path -
/// the `x`/`Ctrl-q` keybinds the close gate intercepts, but also `Ctrl-c`,
/// `Ctrl-d`, an agent exiting, or a crash, none of which route through the
/// plugin - can drop the last right-side pane to zero. When that happens
/// the sidebar takes focus, `spawn_blank_pane` refuses ("cannot create
/// panes from the sidebar"), and the user is stranded with no way back.
