    if self.mode != Mode::Todos || !self.permitted {
        return;
    }
    if self.content_pane_count() > 0 {
        self.seen_content_pane = true;
        self.respawn_in_flight = false;
        return;
    }
    if !self.seen_content_pane || self.respawn_in_flight {
        return;
    }
    let dead = self
        .panes
        .iter()
        .find(|p| !p.floating && p.exited)
        .map(|p| p.id);
    let spawned = match dead {
        Some(target) => self.respawn_empty_viewer_in_place(target),
        None => self.spawn_empty_viewer(),
    };
    if spawned.is_some() {
        self.respawn_in_flight = true;
    }
}

